// HasChurch applies the HasEdge predicate on the "church" edge.
func HasChurch() predicate.ProgramEntry {
	return predicate.ProgramEntry(func(s *sql.Selector) {
		step := sqlgraph.NewStep(
			sqlgraph.From(Table, FieldID),
			sqlgraph.Edge(sqlgraph.M2O, true, ChurchTable, ChurchColumn),
		)
		sqlgraph.HasNeighbors(s, step)
	})
}

// HasChurchWith applies the HasEdge predicate on the "church" edge with a given conditions (other predicates).
func HasChurchWith(preds ...predicate.Church) predicate.ProgramEntry {
	return predicate.ProgramEntry(func(s *sql.Selector) {
		step := newChurchStep()
		sqlgraph.HasNeighborsWith(s, step, func(s *sql.Selector) {
			for _, p := range preds {
				p(s)
			}
		})
	})
}

// And groups predicates with the AND operator between them.
func And(predicates ...predicate.ProgramEntry) predicate.ProgramEntry {
	return predicate.ProgramEntry(sql.AndPredicates(predicates...))
}

// Or groups predicates with the OR operator between them.
func Or(predicates ...predicate.ProgramEntry) predicate.ProgramEntry {
	return predicate.ProgramEntry(sql.OrPredicates(predicates...))
}

// Not applies the not operator on the given predicate.
func Not(p predicate.ProgramEntry) predicate.ProgramEntry {
	return predicate.ProgramEntry(sql.NotPredicates(p))
}
